import { useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] = useState([]);
  const [searched, setSearched] = useState(false);

  const [workType, setWorkType] = useState("");
  const [location, setLocation] = useState("");
  const [date, setDate] = useState("");

  const user = JSON.parse(localStorage.getItem("user"));

  // =========================
  // SEARCH WORKERS (REAL)
  // =========================
  const searchWorkers = async () => {

    try {

      const res = await axios.get("http://localhost:5000/api/auth/workers");

      const filtered = res.data.filter(w =>
        w.skills?.some(s =>
          s.toLowerCase().includes(workType.toLowerCase())
        ) &&
        w.city?.toLowerCase().includes(location.toLowerCase())
      );

      setWorkers(filtered);
      setSearched(true);

    } catch (err) {
      console.log(err);
    }
  };

  // =========================
  // SEND REQUEST
  // =========================
  const sendRequest = async (worker) => {

    await axios.post("http://localhost:5000/api/request/send", {
      customerName: user.name,
      customerId: user._id,

      labourId: worker._id,
      labourName: worker.name,

      workType,
      location,
      date,
      timings: []
    });

    alert("Request sent");
  };

  return (

    <div>

      <Navbar />

      <div className="container">

        <h2>Customer Dashboard</h2>

        {/* SEARCH BOX */}
        <div className="card">

          <input
            className="input"
            placeholder="Work type"
            onChange={(e) => setWorkType(e.target.value)}
          />

          <input
            className="input"
            placeholder="Location"
            onChange={(e) => setLocation(e.target.value)}
          />

          <input
            className="input"
            type="date"
            onChange={(e) => setDate(e.target.value)}
          />

          <button className="btn btn-primary" onClick={searchWorkers}>
            Search Workers
          </button>

        </div>

        {/* EMPTY STATE */}
        {!searched && (
          <div style={{ textAlign: "center", marginTop: 40, color: "#777" }}>
            Search to see available workers
          </div>
        )}

        {/* RESULTS */}
        {searched && (

          <div className="grid" style={{ marginTop: 20 }}>

            {workers.length === 0 ? (

              <div className="card">
                No workers found
              </div>

            ) : (

              workers.map((w) => (

                <div className="card" key={w._id}>

                  <h3>{w.name}</h3>
                  <p>{w.skills?.join(", ")}</p>
                  <p>📍 {w.city}</p>

                  <button
                    className="btn btn-primary"
                    onClick={() => sendRequest(w)}
                  >
                    Send Request
                  </button>

                  {/* STATUS PLACEHOLDER */}
                  <div style={{ marginTop: 10, fontSize: 14 }}>

                    <p>Status: Pending</p>
                    <p>Price: --</p>
                    <p>Decision: Waiting</p>

                  </div>

                </div>

              ))

            )}

          </div>

        )}

      </div>

    </div>
  );
}
